    'GMT': 0,
    'EST': -5,
    'EDT': -4,
    'PST': -8,
    'PDT': -7
  };

  const match = s.match(/^(\d{4})-(\d{2})-(\d{2})\s+(\d{2}):(\d{2}):(\d{2})\s+([A-Z]+)$/);

  if (!match) {
    return null;
  }

  const [, year, month, day, hour, minute, second, abbr] = match;

  if (!(abbr in abbrToOffset)) {
    return null;
  }

  const offsetHours = abbrToOffset[abbr];

  try {
    const plainDateTime = Temporal.PlainDateTime.from({
      year: parseInt(year, 10),
      month: parseInt(month, 10),
      day: parseInt(day, 10),
      hour: parseInt(hour, 10),
      minute: parseInt(minute, 10),
      second: parseInt(second, 10)
    });

    const offsetMinutes = offsetHours * 60;
    const instant = plainDateTime.toZonedDateTime('UTC').toInstant().subtract({ minutes: offsetMinutes });

    const offsetStr = offsetHours >= 0 ? `+${String(offsetHours).padStart(2, '0')}:00` : `-${String(Math.abs(offsetHours)).padStart(2, '0')}:00`;
    return instant.toZonedDateTimeISO(`UTC${offsetStr === '+00:00' ? '' : offsetStr}`);
  } catch {
    return null;
  }
}
